import pytest
from merge_sorted import merge_sorted


class TestMergeSortedHappyPath:
    """Tests for normal, expected use cases."""

    def test_merge_two_sorted_lists(self):
        """Test merging two normal sorted lists."""
        assert merge_sorted([1, 3, 5], [2, 4, 6]) == [1, 2, 3, 4, 5, 6]

    def test_merge_lists_with_duplicates(self):
        """Test merging lists containing duplicate values."""
        assert merge_sorted([1, 3, 3, 5], [2, 3, 4]) == [1, 2, 3, 3, 3, 4, 5]

    def test_merge_lists_with_negative_numbers(self):
        """Test merging lists with negative numbers."""
        assert merge_sorted([-5, -2, 0, 3], [-3, 1, 4]) == [-5, -3, -2, 0, 1, 3, 4]

    def test_merge_single_element_lists(self):
        """Test merging lists with single elements."""
        assert merge_sorted([1], [2]) == [1, 2]
        assert merge_sorted([5], [3]) == [3, 5]

    def test_merge_lists_different_lengths(self):
        """Test merging lists of different lengths."""
        assert merge_sorted([1, 2], [3, 4, 5, 6]) == [1, 2, 3, 4, 5, 6]
        assert merge_sorted([1, 2, 3, 4, 5], [6]) == [1, 2, 3, 4, 5, 6]


